            if (totalPackages == 0) {
                totalPackages = total;
                fileName = json.optString("fileName", "reconstructed_file");
                expectedChecksum = json.optString("checksum", "");
                encoding = json.optString("encoding", "Base64");
                Log.d(TAG, "Initiated: Total=" + totalPackages + ", File=" + fileName);
            }

            // 检查总数是否一致
            if (total != totalPackages) {
                if (listener != null) listener.onError("包总数不一致！期望:" + totalPackages + " 实际:" + total);
                return false;
            }
            // 存入 TreeMap (自动排序)
            dataChunks.put(currentNum, content);

            if (listener != null) {
                listener.onProgress(dataChunks.size(), totalPackages);
            }

            Log.d(TAG, "Received chunk " + currentNum + "/" + totalPackages);
            // 检查是否收集完毕
            if (dataChunks.size() == totalPackages) {
                reconstructFile();
                return true; // 完成
            }

            return false; // 未完成

        } catch (Exception e) {
            Log.e(TAG, "Error processing chunk", e);
            if (listener != null) listener.onError("解析 JSON 失败：" + e.getMessage());
            return false;
        }
    }
    /**
     * 执行文件重组
     */
    private void reconstructFile() {
        try {
            StringBuilder fullDataBuilder = new StringBuilder();
            for (String chunk : dataChunks.values()) {
                fullDataBuilder.append(chunk);
            }

            String fullDataBase64 = fullDataBuilder.toString();
            byte[] fileBytes;

            if ("Base64".equalsIgnoreCase(encoding)) {
                fileBytes = Base64.decode(fullDataBase64, Base64.DEFAULT);
            } else {
                // 如果不是 Base64，直接取字节 (假设是纯文本或其他编码，这里简化处理)
                fileBytes = fullDataBase64.getBytes();
            }

            // 计算实际 Checksum (MD5)
            String actualChecksum = calculateMD5(fileBytes);

            // 校验
            if (expectedChecksum != null && !expectedChecksum.isEmpty() && !expectedChecksum.equalsIgnoreCase(actualChecksum)) {
                if (listener != null) listener.onChecksumMismatch(expectedChecksum, actualChecksum);
                return;
            }

            // 保存文件 (保存到应用私有目录或外部存储，此处演示保存到外部存储 Download 目录)
            // 注意：Android 10+ 需要使用 MediaStore 或 getExternalFilesDir
            File outputDir = new File(android.os.Environment.getExternalStoragePublicDirectory(android.os.Environment.DIRECTORY_DOWNLOADS), "QRReconstructor");
            if (!outputDir.exists()) {
                outputDir.mkdirs();
            }

            File outputFile = new File(outputDir, fileName);
            FileOutputStream fos = new FileOutputStream(outputFile);
            fos.write(fileBytes);
            fos.close();

            Log.d(TAG, "File saved to: " + outputFile.getAbsolutePath());
            if (listener != null) listener.onSuccess(outputFile, "文件还原成功！大小：" + fileBytes.length + " 字节");

            // 完成后自动重置，准备下一次任务 (可选)
            // reset(); 

        } catch (Exception e) {
            Log.e(TAG, "Error reconstructing file", e);
            if (listener != null) listener.onError("文件重组失败：" + e.getMessage());
        }
    }

    /**
     * 计算字节数组的 MD5 值
     */
    private String calculateMD5(byte[] data) throws Exception {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] digest = md.digest(data);
        StringBuilder sb = new StringBuilder();
        for (byte b : digest) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    /**
     * 获取当前进度
     */
    public int getCurrentCount() {
        return dataChunks.size();
    }

    public int getTotalCount() {
        return totalPackages;
    }
}

package com.example.qrfilereconstructor;
import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;
import androidx.core.content.ContextCompat;
import java.io.File;
public class MainActivity extends AppCompatActivity implements FileReconstructor.ReconstructionListener {
    private static final int REQUEST_CAMERA_PERMISSION = 100;
    private static final int REQUEST_SCAN_CODE = 101;
    private TextView tvStatus;
    private TextView tvProgress;
    private Button btnScan;
    private Button btnReset;

    private FileReconstructor reconstructor;
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        tvStatus = findViewById(R.id.tvStatus);
        tvProgress = findViewById(R.id.tvProgress);
        btnScan = findViewById(R.id.btnScan);
        btnReset = findViewById(R.id.btnReset);
        // 初始化重组器
        reconstructor = new FileReconstructor(this);
        btnScan.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                checkPermissionAndScan();
            }
        });
        btnReset.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                reconstructor.reset();
                updateUI(0, 0, "已重置，请开始扫描");
                Toast.makeText(MainActivity.this, "已重置", Toast.LENGTH_SHORT).show();
            }
        });

        updateUI(0, 0, "准备就绪");
    }
    private void checkPermissionAndScan() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                != PackageManager.PERMISSION_GRANTED) {
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.CAMERA},
                    REQUEST_CAMERA_PERMISSION);
        } else {
            startScanner();
        }
    }
    private void startScanner() {
        Intent intent = new Intent(this, QRScannerActivity.class);
        startActivityForResult(intent, REQUEST_SCAN_CODE);
    }
    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == REQUEST_CAMERA_PERMISSION) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                startScanner();
            } else {
                Toast.makeText(this, "需要相机权限才能扫码", Toast.LENGTH_LONG).show();
            }
        }
    }
    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        super.onActivityResult(requestCode, resultCode, data);
        if (requestCode == REQUEST_SCAN_CODE && resultCode == RESULT_OK && data != null) {
            String scannedJson = data.getStringExtra("SCAN_RESULT");
            if (scannedJson != null) {
                tvStatus.setText("正在处理...");
                boolean isComplete = reconstructor.processChunk(scannedJson);
                if (!isComplete) {
                     // 如果未完成，可以选择自动继续扫码或者等待用户手动点击
                     // 这里为了用户体验，提示用户继续扫
                     Toast.makeText(this, "分片接收中...", Toast.LENGTH_SHORT).show();
                }
            }
        }
    }
    // --- 回调接口实现 ---
    @Override
    public void onProgress(int current, int total) {
        updateUI(current, total, "收集中...");
    }
    @Override
    public void onSuccess(File file, String message) {
        updateUI(reconstructor.getTotalCount(), reconstructor.getTotalCount(), message);
        Toast.makeText(this, "✅ " + message, Toast.LENGTH_LONG).show();
        // 可以在这里跳转到文件查看界面或者分享文件
    }
    @Override
    public void onError(String error) {
        tvStatus.setText("❌ 错误：" + error);
        Toast.makeText(this, "❌ " + error, Toast.LENGTH_LONG).show();
    }
    @Override
    public void onChecksumMismatch(String expected, String actual) {
        String msg = "校验失败！\n期望：" + expected + "\n实际：" + actual;
        tvStatus.setText("❌ " + msg);
        Toast.makeText(this, msg, Toast.LENGTH_LONG).show();
        // 校验失败通常意味着数据损坏或扫描错误，建议重置
        reconstructor.reset();
        updateUI(0, 0, "校验失败，已重置");
    }
    private void updateUI(int current, int total, String statusText) {
        tvStatus.setText(statusText);
        if (total > 0) {
            tvProgress.setText(String.format("进度：%d / %d", current, total));
        } else {
            tvProgress.setText("进度：- / -");
        }
    }
}

package com.example.qrfilereconstructor;
import android.content.Intent;
import android.os.Bundle;
import android.util.Log;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import com.google.zxing.Result;
import me.dm7.barcodescanner.zxing.ZXingScannerView;
/**
 * 扫码界面
 * 使用 ZXingScannerView 进行快速集成
 */
public class QRScannerActivity extends AppCompatActivity implements ZXingScannerView.ResultHandler {
    private static final String TAG = "QRScannerActivity";
    private ZXingScannerView scannerView;
    @Override
    public void onCreate(Bundle state) {
        super.onCreate(state);
        scannerView = new ZXingScannerView(this);
        setContentView(scannerView);
    }
    @Override
    public void onResume() {
        super.onResume();
        scannerView.setResultHandler(this);
        scannerView.startCamera();
    }
    @Override
    public void onPause() {
        super.onPause();
        scannerView.stopCamera();
    }
    @Override
    public void handleResult(Result rawResult) {
        String contents = rawResult.getText();
        Log.d(TAG, "Scanned: " + contents);
        // 简单验证是否为 JSON 格式 (可选，防止误扫其他码)
        if (contents != null && contents.trim().startsWith("{")) {
            Intent resultIntent = new Intent();
            resultIntent.putExtra("SCAN_RESULT", contents);
            setResult(RESULT_OK, resultIntent);
            finish(); // 扫描成功，返回主界面
        } else {
            Toast.makeText(this, "非有效数据二维码，请重试", Toast.LENGTH_SHORT).show();
            // 延迟后继续扫描
            scannerView.resumeCameraPreview(this);
        }
    }
}

